<template>
  <section class="growth-workspace">
    <header class="growth-header">
      <div><p class="eyebrow">成长记录</p><h1>让投入留下可见的轨迹。</h1><p>管理长期关注的能力，查看每次行动留下的成长与积分记录。</p></div>
      <div class="balance-display"><span>可用积分</span><strong>{{ balance }}</strong><small>完成行动即可积累</small></div>
    </header>

    <div v-if="isLoading" class="loading-state"><el-icon class="is-loading"><Loading /></el-icon><span>正在加载成长记录...</span></div>
    <div v-else-if="loadError" class="growth-error" role="alert"><el-icon><WarningFilled /></el-icon><div><strong>成长记录暂时无法加载</strong><p>{{ loadError }}</p></div><el-button :icon="Refresh" @click="loadGrowth">重新加载</el-button></div>
    <template v-else>
      <section class="growth-section" aria-labelledby="attributes-title">
        <div class="section-heading"><div><p class="eyebrow">能力方向</p><h2 id="attributes-title">我想持续投入什么</h2></div><el-button type="primary" :icon="Plus" @click="openCreate">添加方向</el-button></div>
        <div v-if="attributes.length" class="attribute-list"><article v-for="attribute in attributes" :key="attribute.attr_id" class="attribute-row"><div class="attribute-row__title"><span class="attribute-row__mark"></span><span><strong>{{ attribute.attr_name }}</strong><small>{{ attribute.description || '还没有添加说明。' }}</small></span></div><div class="attribute-row__progress"><div><span>当前进度</span><strong>{{ attribute.attr_value || 0 }} / {{ attribute.max_value || 100 }}</strong></div><el-progress :percentage="attributeProgress(attribute)" :show-text="false" :stroke-width="7" /></div><div class="attribute-row__actions"><el-button text :icon="EditPen" title="编辑" @click="openEdit(attribute)" /><el-button text type="danger" :icon="Delete" title="删除" @click="removeAttribute(attribute)" /></div></article></div>
        <div v-else class="empty-state"><el-icon><TrendCharts /></el-icon><h3>还没有成长方向</h3><p>先添加一项你希望长期练习的能力，行动完成时可以把成长记录下来。</p><el-button type="primary" @click="openCreate">添加方向</el-button></div>
      </section>
      <section class="growth-section activity-section" aria-labelledby="activity-title"><div class="section-heading"><div><p class="eyebrow">积分流动</p><h2 id="activity-title">最近记录</h2></div></div><div v-if="activities.length" class="activity-list"><div v-for="activity in activities" :key="activity.id || activity.created_at + activity.amount" class="activity-row"><span class="activity-row__mark" :class="Number(activity.amount) >= 0 ? 'activity-row__mark--plus' : 'activity-row__mark--minus'"></span><span><strong>{{ activityLabel(activity) }}</strong><small>{{ formatDate(activity.created_at) }}</small></span><b :class="Number(activity.amount) >= 0 ? 'is-positive' : 'is-negative'">{{ Number(activity.amount) >= 0 ? '+' : '' }}{{ activity.amount || 0 }}</b></div></div><p v-else class="muted-copy">还没有积分记录。完成一次行动后，这里会出现第一条记录。</p></section>
    </template>

    <el-dialog v-model="editorVisible" :title="editingAttribute ? '编辑成长方向' : '添加成长方向'" width="min(520px, calc(100vw - 28px))" :close-on-click-modal="false"><el-form label-position="top" @submit.prevent="saveAttribute"><el-form-item label="名称" required><el-input v-model="attributeDraft.attr_name" maxlength="50" show-word-limit placeholder="例如：写作、专注、表达" /></el-form-item><el-form-item label="说明"><el-input v-model="attributeDraft.description" type="textarea" :rows="3" maxlength="200" show-word-limit placeholder="它对你意味着什么，或希望如何练习" /></el-form-item><div class="form-grid"><el-form-item label="当前进度"><el-input-number v-model="attributeDraft.attr_value" :min="0" :max="999" controls-position="right" /></el-form-item><el-form-item label="阶段上限"><el-input-number v-model="attributeDraft.max_value" :min="1" :max="999" controls-position="right" /></el-form-item></div></el-form><template #footer><el-button @click="editorVisible = false">取消</el-button><el-button type="primary" :loading="isSaving" :disabled="!attributeDraft.attr_name.trim()" @click="saveAttribute">保存</el-button></template></el-dialog>
  </section>
</template>

<script setup>
import { onMounted, reactive, ref } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { Delete, EditPen, Loading, Plus, Refresh, TrendCharts, WarningFilled } from '@element-plus/icons-vue'
import { growthProfileApi } from '@/api/growthProfile'
import { formatAxiosErrorMessage } from '@/utils/apiPayload'

const balance = ref(0)
const attributes = ref([])
const activities = ref([])
const isLoading = ref(true)
const loadError = ref('')
const isSaving = ref(false)
const editorVisible = ref(false)
const editingAttribute = ref(null)
const attributeDraft = reactive(defaultAttribute())

function defaultAttribute() { return { attr_name: '', description: '', attr_value: 0, max_value: 100 } }
function resetDraft(attribute = null) { Object.assign(attributeDraft, attribute ? { attr_name: attribute.attr_name || '', description: attribute.description || '', attr_value: Number(attribute.attr_value || 0), max_value: Number(attribute.max_value || 100) } : defaultAttribute()) }
function attributeProgress(attribute) { const max = Math.max(1, Number(attribute.max_value || 100)); return Math.min(100, Math.round(Number(attribute.attr_value || 0) / max * 100)) }
function activityLabel(activity) { return activity.description || activity.source || (Number(activity.amount) >= 0 ? '完成行动获得积分' : '积分调整') }
function formatDate(value) { if (!value) return '刚刚'; const date = new Date(value); return Number.isNaN(date.getTime()) ? String(value) : date.toLocaleDateString('zh-CN', { month: 'numeric', day: 'numeric', hour: '2-digit', minute: '2-digit' }) }
function openCreate() { editingAttribute.value = null; resetDraft(); editorVisible.value = true }
function openEdit(attribute) { editingAttribute.value = attribute; resetDraft(attribute); editorVisible.value = true }
async function loadGrowth() { isLoading.value = true; loadError.value = ''; try { const [loadedBalance, loadedAttributes, loadedActivity] = await Promise.all([growthProfileApi.getGrowthPoints(), growthProfileApi.listAttributes(), growthProfileApi.listGrowthPointActivity({ limit: 12 })]); balance.value = Number(loadedBalance?.growth_points || 0); attributes.value = Array.isArray(loadedAttributes) ? loadedAttributes : []; activities.value = Array.isArray(loadedActivity?.history) ? loadedActivity.history : [] } catch (error) { loadError.value = formatAxiosErrorMessage(error, '请检查服务连接后重试。已有成长记录不会丢失。'); ElMessage.error('成长记录暂时无法加载') } finally { isLoading.value = false } }
async function saveAttribute() { if (!attributeDraft.attr_name.trim()) return; isSaving.value = true; const data = { attr_name: attributeDraft.attr_name.trim(), description: attributeDraft.description.trim(), attr_value: Number(attributeDraft.attr_value || 0), max_value: Number(attributeDraft.max_value || 100) }; try { if (editingAttribute.value) { await growthProfileApi.updateAttribute(editingAttribute.value.attr_id, data) } else { const created = await growthProfileApi.createAttribute({ attr_name: data.attr_name, description: data.description, max_value: data.max_value }); if (data.attr_value > 0 && created?.attr_id) await growthProfileApi.updateAttribute(created.attr_id, { attr_value: data.attr_value }) } editorVisible.value = false; ElMessage.success(editingAttribute.value ? '成长方向已更新' : '成长方向已添加'); await loadGrowth() } catch (error) { ElMessage.error(formatAxiosErrorMessage(error, '保存成长方向失败。')) } finally { isSaving.value = false } }
async function removeAttribute(attribute) { try { await ElMessageBox.confirm('确定删除“' + attribute.attr_name + '”吗？这不会影响已经完成的行动记录。', '删除成长方向', { type: 'warning', confirmButtonText: '删除', cancelButtonText: '取消' }); await growthProfileApi.deleteAttribute(attribute.attr_id); ElMessage.success('成长方向已删除'); await loadGrowth() } catch (error) { if (error !== 'cancel' && error !== 'close') ElMessage.error(formatAxiosErrorMessage(error, '删除成长方向失败。')) } }
onMounted(loadGrowth)
</script>

<style scoped>
.growth-workspace { padding: 38px 0 54px; }.growth-header { display: flex; align-items: stretch; justify-content: space-between; gap: 28px; padding-bottom: 28px; border-bottom: 1px solid var(--border-color-light); }.eyebrow { margin: 0 0 6px; color: var(--color-primary); font-size: 12px; font-weight: 700; letter-spacing: 0; }.growth-workspace h1, .growth-workspace h2, .growth-workspace h3, .growth-workspace p { margin-top: 0; }.growth-workspace h1 { margin-bottom: 8px; color: var(--text-primary); font-size: 27px; line-height: 1.26; }.growth-header p:not(.eyebrow) { max-width: 590px; margin-bottom: 0; color: var(--text-secondary); font-size: 14px; line-height: 1.65; }.balance-display { display: grid; flex: 0 0 180px; align-content: center; gap: 4px; padding: 20px 22px; border-left: 3px solid var(--color-primary); background: color-mix(in srgb, var(--color-primary) 6%, transparent); }.balance-display span, .balance-display small { color: var(--text-secondary); font-size: 12px; }.balance-display strong { color: var(--color-primary-dark); font-size: 31px; line-height: 1.05; }.growth-section { padding: 30px 0; border-bottom: 1px solid var(--border-color-light); }.section-heading { display: flex; align-items: flex-end; justify-content: space-between; gap: 16px; margin-bottom: 16px; }.section-heading .eyebrow { margin-bottom: 3px; }.section-heading h2 { margin-bottom: 0; color: var(--text-primary); font-size: 17px; }.attribute-list { border-top: 1px solid var(--border-color-light); }.attribute-row { display: grid; grid-template-columns: minmax(190px, .9fr) minmax(230px, 1.3fr) auto; gap: 28px; align-items: center; padding: 17px 0; border-bottom: 1px solid var(--border-color-light); }.attribute-row__title { display: flex; align-items: flex-start; gap: 10px; min-width: 0; }.attribute-row__mark { flex: 0 0 8px; width: 8px; height: 8px; margin-top: 6px; border-radius: 50%; background: var(--color-primary); }.attribute-row__title > span:last-child { display: grid; min-width: 0; gap: 4px; }.attribute-row strong, .activity-row strong { overflow: hidden; color: var(--text-primary); font-size: 14px; text-overflow: ellipsis; white-space: nowrap; }.attribute-row small, .activity-row small { overflow: hidden; color: var(--text-secondary); font-size: 12px; line-height: 1.4; text-overflow: ellipsis; white-space: nowrap; }.attribute-row__progress { display: grid; gap: 8px; }.attribute-row__progress > div { display: flex; justify-content: space-between; gap: 12px; color: var(--text-muted); font-size: 12px; }.attribute-row__progress strong { color: var(--text-secondary); font-size: 12px; }.attribute-row__actions { display: flex; gap: 2px; }.activity-list { border-top: 1px solid var(--border-color-light); }.activity-row { display: flex; align-items: center; gap: 9px; padding: 12px 0; border-bottom: 1px solid var(--border-color-light); }.activity-row__mark { flex: 0 0 7px; width: 7px; height: 7px; border-radius: 50%; background: var(--color-success); }.activity-row__mark--minus { background: var(--color-warning); }.activity-row > span:nth-child(2) { display: grid; flex: 1; min-width: 0; gap: 3px; }.activity-row b { font-size: 13px; }.is-positive { color: var(--color-success); }.is-negative { color: var(--color-warning); }.muted-copy { margin-bottom: 0; color: var(--text-muted); font-size: 13px; line-height: 1.6; }.growth-error { display:grid; grid-template-columns:auto minmax(0,1fr) auto; align-items:center; gap:14px; margin:28px 0 0; padding:18px; border:1px solid color-mix(in srgb,var(--color-danger) 24%,var(--border-color)); border-radius:7px; background:color-mix(in srgb,var(--color-danger) 5%,var(--bg-secondary)); }.growth-error > .el-icon { color:var(--color-danger); font-size:22px; }.growth-error strong { color:var(--text-primary); font-size:14px; }.growth-error p { margin:4px 0 0; color:var(--text-secondary); font-size:13px; line-height:1.5; }.loading-state { display: grid; grid-template-columns: auto auto; justify-content: center; gap: 10px; padding: 100px 20px; color: var(--text-muted); }.empty-state { display: grid; justify-items: start; gap: 9px; padding: 46px 0 16px; color: var(--text-muted); }.empty-state > .el-icon { color: var(--color-primary); font-size: 30px; }.empty-state h3 { margin-bottom: 0; color: var(--text-primary); font-size: 17px; }.empty-state p { max-width: 430px; margin-bottom: 4px; color: var(--text-secondary); font-size: 13px; line-height: 1.6; }.form-grid { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 16px; }.form-grid :deep(.el-input-number) { width: 100%; }@media (max-width: 800px) {.attribute-row { grid-template-columns: minmax(0, 1fr) auto; gap: 14px; }.attribute-row__progress { grid-column: 1 / -1; }.attribute-row__actions { grid-column: 2; grid-row: 1; } }@media (max-width: 640px) { .growth-error { grid-template-columns:auto minmax(0,1fr); }.growth-error .el-button { grid-column:1/-1; width:100%; } .growth-workspace { padding: 26px 0 42px; }.growth-header { align-items: flex-start; flex-direction: column; }.growth-workspace h1 { font-size: 23px; }.balance-display { width: 100%; box-sizing: border-box; }.attribute-row small, .activity-row small { white-space: normal; }.form-grid { grid-template-columns: 1fr; gap: 0; } }
</style>
